mapper.select:
SELECT
(
SELECT COUNT(*)
FROM user_learning_record ulr
WHERE ulr.user_id = #{userId}
AND ulr.created_at >= #{start}
AND ulr.created_at <= #{end}
) AS validLearningEventCount,

(
SELECT COUNT(DISTINCT DATE(ulr.created_at))
FROM user_learning_record ulr
WHERE ulr.user_id = #{userId}
AND ulr.created_at >= #{start}
AND ulr.created_at <= #{end}
) AS activeDays,

(
SELECT COALESCE(
ROUND(
SUM(
COALESCE(ucrp.max_position_seconds, 0)
) / 60
),
0
)
FROM user_course_resource_progress ucrp
WHERE ucrp.user_id = #{userId}
AND ucrp.updated_at > #{start}
AND ucrp.updated_at <= #{end}
) AS studyMinutes,

(
SELECT COUNT(*)
FROM user_course_point_progress ucpp
WHERE ucpp.user_id = #{userId}
AND ucpp.status = 2
AND ucpp.completed_at > #{start}
AND ucpp.completed_at <= #{end}
) AS completedPoints,

(
SELECT COUNT(*)
FROM assessment_attempt aa
WHERE aa.user_id = #{userId}
AND aa.status = 2
AND aa.submitted_at > #{start}
AND aa.submitted_at <= #{end}
) AS assessmentCount,

(
SELECT COUNT(*)
FROM assessment_answer answer_record
INNER JOIN assessment_attempt attempt_record
ON attempt_record.id = answer_record.attempt_id
WHERE attempt_record.user_id = #{userId}
AND attempt_record.status = 2
AND answer_record.answered_at > #{start}
AND answer_record.answered_at <= #{end}
) AS answeredQuestionCount,

(
SELECT ROUND(AVG(aa.score), 2)
FROM assessment_attempt aa
WHERE aa.user_id = #{userId}
AND aa.status = 2
AND aa.submitted_at > #{start}
AND aa.submitted_at <= #{end}
AND aa.score IS NOT NULL
) AS averageScore
